  'baotou/grass': ('ทริปทุ่งหญ้า', 'เพียงเดินทางออกไปหนึ่งชั่วโมง คุณจะได้พบกับทุ่งหญ้ากว้างใหญ่สุดลูกหูลูกตาพร้อมที่พักแบบกระโจม'),
  'weifang/kite': ('เมืองหลวงแห่งว่าว', 'เมืองนี้ได้ชื่อว่าเป็นเมืองหลวงแห่งว่าวของโลก โดยในเดือนเมษายนของทุกปีจะมีเทศกาลว่าวนานาชาติที่เต็มไปด้วยสีสันบนท้องฟ้า'),
  'weifang/woodprint': ('ภาพพิมพ์ไม้หยางเจียปู้', 'หมู่บ้านแห่งนี้สืบทอดการทำภาพพิมพ์ไม้สำหรับเทศกาลตรุษจีนมานานกว่า 600 ปี'),
  'weifang/dragon': ('ว่าวมังกร', 'ว่าวมังกรที่มีความยาวกว่าร้อยเมตรถือเป็นไฮไลท์สำคัญของเทศกาลว่าว'),
  'weifang/radish': ('หัวไชเท้าเวยฟาง', 'หัวไชเท้าสีเขียวที่มีรสชาติหวานกรอบจนสามารถทานสดได้เหมือนผลไม้ถือเป็นของดีประจำเมือง'),
  'dezhou/chicken': ('ไก่ตุ๋นเต๋อโจว', 'ไก่ตุ๋นเนื้อนุ่มจนหลุดจากกระดูกเมนูนี้เคยเป็นอาหารที่ถวายแด่จักรพรรดิในสมัยก่อน'),
  'dezhou/sun': ('หุบเขาพลังงานแสงอาทิตย์', 'ที่นี่เป็นที่ตั้งของหนึ่งในศูนย์กลางพลังงานแสงอาทิตย์ที่ใหญ่ที่สุดในโลก'),
  'dezhou/grapes': ('สวนเมลอนและองุ่น', 'พื้นที่ราบอันอุดมสมบูรณ์แห่งนี้เต็มไปด้วยเมลอนและองุ่นในช่วงฤดูร้อน'),
  'dezhou/train': ('ท่าเรือคลองขุด', 'ในอดีตที่นี่เคยเป็นท่าเรือขนส่งธัญพืชที่คึกคักที่สุดแห่งหนึ่งในยุคคลองต้ายวิ่นเหอ'),
  'xuzhou/stone': ('ภาพสลักหินสมัยราชวงศ์ฮั่น', 'แผ่นหินจากสุสานสมัยราชวงศ์ฮั่นที่บอกเล่าเรื่องราววิถีชีวิตของผู้คนเมื่อ 2,000 ปีก่อน'),
  'xuzhou/terracotta': ('กองทัพทหารดินเผา', 'มีการขุดพบกองทัพทหารดินเผาที่มีขนาดเล็กกว่าแต่เก่าแก่กว่าที่นี่'),
  'xuzhou/lake': ('ทะเลสาบอวิ๋นหลง', 'พื้นที่ริมทะเลสาบอวิ๋นหลงเปรียบเสมือนปอดสีเขียวของเมืองนี้'),
  'xuzhou/skewer': ('วัฒนธรรมปิ้งย่าง', 'เมืองหลวงแห่งปิ้งย่างของจีนที่อบอวลไปด้วยกลิ่นเนื้อแกะย่างบนเตาถ่านตลอดทั้งคืน'),
  'zhenjiang/vinegar': ('จิ๊กโฉ่วเจิ้นเจียง', 'น้ำส้มสายชูดำที่มีชื่อเสียงที่สุดของจีนซึ่งหมักบ่มสืบทอดกันมานานกว่า 1,400 ปี'),
  'zhenjiang/temple': ('วัดจินซาน', 'วัดที่เป็นฉากในตำนานนางพญางูขาวตั้งตระหง่านอยู่ริมแม่น้ำ'),
  'zhenjiang/pot': ('บะหมี่ฝาหม้อ', 'บะหมี่ฝาหม้อที่ปรุงด้วยการวางฝาหม้อลอยไว้บนน้ำซุปเป็นเมนูอาหารเช้าขึ้นชื่อของท้องถิ่น'),
  'zhenjiang/bridge': ('ริมฝั่งแม่น้ำแยงซี', 'พื้นที่ริมฝั่งแม่น้ำที่รายล้อมไปด้วยสวนสาธารณะสำหรับเดินเล่นชมวิวทิวทัศน์'),
  'jiaxing/zongzi': ('บ๊ะจ่าง', 'ที่นี่คือเมืองหลวงของบ๊ะจ่าง ข้าวเหนียวห่อใบไผ่ที่เป็นเอกลักษณ์'),
  'jiaxing/boat': ('เรือแดงแห่งทะเลสาบหนานหู', 'ในปี ค.ศ. 1921 การประชุมสมัชชาใหญ่พรรคคอมมิวนิสต์ครั้งแรกได้จัดขึ้นบนเรือในทะเลสาบแห่งนี้'),
  'jiaxing/silk': ('เมืองแห่งผ้าไหม', 'ผ้าไหมเจียงหนานถูกทอขึ้นในเมืองริมคลองแห่งนี้มานานหลายศตวรรษ'),
  'jiaxing/canal': ('เมืองน้ำอูเจิ้น', 'ล่องเรือชมเมืองน้ำที่เต็มไปด้วยสะพานหินและแสงไฟจากโคมแดง'),
  'lishui/mountains': ('ยอดเขาเขียวขจี', 'พื้นที่ที่เต็มไปด้วยภูเขามากที่สุดในเจ้อเจียง ซึ่งมีหมู่บ้านบนนาขั้นบันไดตั้งอยู่ท่ามกลางหมู่เมฆ'),
  'lishui/camera': ('สวรรค์ของช่างภาพ', 'นาขั้นบันไดท่ามกลางสายหมอกเป็นหนึ่งในทิวทัศน์ที่ถูกถ่ายภาพมากที่สุดในจีน'),
  'lishui/mushroom': ('ดินแดนแห่งเห็ด', 'อำเภอชิงหยวนถือเป็นแหล่งกำเนิดของการเพาะเห็ดที่สำคัญที่สุดแห่งหนึ่งของโลก'),
  'lishui/raft': ('ล่องแพไม้ไผ่', 'ล่องแพไม้ไผ่ไปตามแม่น้ำโอวเจียงเพื่อชมความงามของหุบเขาเขียวขจี'),
  'anqing/opera': ('งิ้วหวงเหมย', 'ศิลปะการแสดงงิ้วท้องถิ่นที่เป็นที่รักมากที่สุดของจีนได้ถือกำเนิดขึ้นที่นี่'),
  'anqing/pagoda': ('เจดีย์เจิ้นเฟิง', 'เจดีย์เก่าแก่อายุกว่า 400 ปีริมแม่น้ำแยงซีที่ได้รับการขนานนามว่าเป็นประภาคารแห่งแรกของแม่น้ำ'),
  'anqing/tea': ('ชาเยว่ซี', 'ชาเขียวรสเลิศที่มีกลิ่นหอมละมุนซึ่งปลูกบนพื้นที่ลาดชันของเทือกเขาต้าเปี๋ย'),
  'anqing/sail': ('ประตูแม่น้ำ', 'เมืองท่าสำคัญริมแม่น้ำแยงซีในมณฑลอันฮุย ซึ่งชื่อเมืองมีความหมายว่าการเฉลิมฉลองอย่างสงบสุข'),
  'ganzhou/orange': ('ส้มนาเวลก้านหนาน', 'ส้มนาเวลที่หวานที่สุดในจีนเติบโตได้ดีในดินสีแดงของภูมิภาคนี้'),
  'ganzhou/house': ('บ้านดินชาวฮากกา', 'วัฒนธรรมชาวฮากกาที่สืบทอดมานานหลายศตวรรษในบ้านทรงกลมที่สร้างขึ้นเหมือนป้อมปราการ'),
  'ganzhou/pavilion': ('ศาลาอวี้กู', 'ศาลาที่กวีสมัยราชวงศ์ซ่งเคยแต่งบทกวีถึง ซึ่งตั้งอยู่บนจุดที่แม่น้ำสองสายมาบรรจบกัน'),
  'ganzhou/star': ('จุดเริ่มต้นการเดินทัพทางไกล', 'เมืองนี้เป็นจุดเริ่มต้นของการเดินทัพทางไกลของกองทัพแดง'),
  'putian/shrine': ('ศาลเจ้าแม่หม่าโจ้ว', 'เจ้าแม่หม่าโจ้วเทพีผู้คุ้มครองชาวเรือประสูติที่นี่ และศาลเจ้าหลักของท่านตั้งอยู่บนเกาะเหมยโจว'),
  'putian/lychee': ('สวนลิ้นจี่', 'ต้นลิ้นจี่ที่มีอายุนับพันปีทำให้เมืองนี้ได้รับฉายาว่าเป็นดินแดนแห่งลิ้นจี่'),
  'putian/shoe': ('เมืองหลวงแห่งรองเท้า', 'สัดส่วนการผลิตรองเท้ากีฬาจำนวนมหาศาลของโลกมาจากโรงงานในเมืองนี้'),
  'putian/wave': ('เกาะเหมยโจว', 'เกาะที่เดินทางไปถึงได้ด้วยเรือเฟอร์รี่แห่งนี้มีชื่อเสียงจากชายหาดที่สวยงามและเทศกาลในวัดวาอาราม'),
  'mudanjiang/snow': ('หมู่บ้านหิมะ', 'หมู่บ้านในเทพนิยายที่ถูกปกคลุมด้วยหิมะหนานุ่มและส่องประกายงดงามในช่วงฤดูหนาว'),
  'mudanjiang/lake': ('ทะเลสาบจิ้งปัว', 'ทะเลสาบที่เกิดจากการระเบิดของภูเขาไฟซึ่งมีน้ำตกเตี้ยวสุ่ยโหลวที่ยังคงไหลแม้ในฤดูหนาว'),
  'mudanjiang/tiger': ('สวนเสือไซบีเรีย', 'หนึ่งในเขตรักษาพันธุ์เสือไซบีเรียที่ใหญ่ที่สุดในโลก'),
  'mudanjiang/ski': ('ฤดูกาลเล่นสกี', 'ฤดูหนาวที่มีหิมะตกยาวนานทำให้ภูมิภาคนี้เป็นจุดหมายปลายทางที่นักสกีทุกคนต้องมาเยือน'),
  'changzhou/dino': ('สวนไดโนเสาร์', 'สวนสนุกธีมไดโนเสาร์ที่มีชื่อเสียงที่สุดของจีนและเป็นสัญลักษณ์สำหรับครอบครัวของเมืองนี้'),
  'changzhou/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์ที่สูงที่สุดในโลกด้วยความสูง 153 เมตรตั้งตระหง่านอยู่ใจกลางเมือง'),
  'changzhou/comb': ('งานหัตถกรรมหวี', 'หวีจากฉางโจวที่มีประวัติศาสตร์ยาวนานนับพันปีเคยเป็นของกำนัลล้ำค่าในราชสำนัก'),
  'changzhou/canal': ('คลองต้ายวิ่นเหอ', 'ริมฝั่งคลองเป็นจุดเดินเล่นยอดนิยมเพื่อชมย่านเมืองเก่าและแสงสีในยามค่ำคืน'),
  'shaoxing/wine': ('เหล้าเส้าซิง', 'เหล้าข้าวสีเหลืองที่มีชื่อเสียงในการปรุงอาหารจีนแห่งนี้มีการหมักบ่มมานานนับพันปี'),
  'shaoxing/bridge': ('สะพานหินโบราณ', 'เมืองเส้าซิงที่เต็มไปด้วยลำคลองยังคงอนุรักษ์สะพานหินโค้งไว้หลายร้อยแห่ง'),
  'shaoxing/pen': ('แหล่งกำเนิดอักษรวิจิตร', 'ศาลาหลานถิงของปรมาจารย์หวังซีจือถือเป็นสถานที่ศักดิ์สิทธิ์แห่งศิลปะการเขียนพู่กันจีน'),
  'shaoxing/boat': ('เรืออูเผิง', 'เรือพายหลังคาดำที่ใช้เท้าถีบเป็นพาหนะคลาสสิกสำหรับการล่องไปตามลำคลอง'),
  'bengbu/shell': ('ท่าเรือไข่มุก', 'ชื่อของเมืองมีความหมายว่าท่าเรือหอย ซึ่งในอดีตเคยมีชื่อเสียงโด่งดังจากการผลิตไข่มุกแม่น้ำหวย'),
  'bengbu/train': ('สถานีรถไฟเปิ่งปู้', 'เมืองนี้เติบโตขึ้นจากการเป็นจุดเชื่อมต่อสำคัญของเส้นทางรถไฟสายเหนือ-ใต้ที่ตัดผ่านแม่น้ำหวย'),
  'bengbu/river': ('แม่น้ำหวย', 'แม่น้ำสายสำคัญที่เป็นเส้นแบ่งเขตทางภูมิศาสตร์ระหว่างจีนเหนือและจีนใต้ไหลผ่านที่เมืองนี้'),
  'bengbu/blossom': ('เทศกาลชมดอกไม้', 'ในช่วงฤดูใบไม้ผลิ สวนสาธารณะริมแม่น้ำจะเต็มไปด้วยบรรยากาศของเทศกาลชมดอกไม้ที่สวยงาม'),
  'jiujiang/mountain': ('เขาหลูซาน', 'ยอดเขาที่ปกคลุมด้วยสายหมอกแห่งนี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกและเป็นแรงบันดาลใจให้แก่กวีและจิตรกรมากมาย'),
  'jiujiang/tea': ('ชาอวิ๋นอู้', 'ชาที่ปลูกบนไหล่เขาหลูซานขึ้นชื่อว่าเป็นหนึ่งในชาที่มีรสชาติละมุนที่สุดของจีน'),
  'jiujiang/lake': ('ทะเลสาบโผหยาง', 'ทะเลสาบน้ำจืดที่ใหญ่ที่สุดในจีนแห่งนี้เป็นแหล่งอาศัยของนกกระเรียนนับพันตัวในช่วงฤดูหนาว'),
  'jiujiang/scroll': ('เมืองแห่งบทกวี', 'ประตูเมืองริมน้ำแห่งนี้เคยเป็นสถานที่ที่กวีเอกอย่างไป๋จวีอี้และซูซื่อได้รังสรรค์บทกวีอันเลื่องชื่อไว้'),
  'quanzhou/ship': ('เส้นทางสายไหมทางทะเล', 'เมืองท่าที่ยิ่งใหญ่ที่สุดในยุคกลางแห่งนี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกและเป็นที่รู้จักในชื่อ \'จายตุน\' ตามบันทึกของมาร์โก โปโล'),
  'quanzhou/mosque': ('มัสยิดชิงจิ้ง', 'มัสยิดหินเก่าแก่ที่สร้างขึ้นในปี ค.ศ. 1009 แห่งนี้ถือเป็นหนึ่งในมัสยิดที่เก่าแก่ที่สุดในประเทศจีน'),
  'quanzhou/puppet': ('หุ่นเชิดฉวนโจว', 'ศิลปะการแสดงหุ่นเชิดแบบชักใยของเมืองฉวนโจวเป็นประเพณีการแสดงที่มีประวัติศาสตร์ยาวนานนับพันปี'),
  'quanzhou/tea': ('ชาทิกวนอิม', 'ชาอูหลงจากเมืองอันซีที่อยู่ใกล้เคียงเป็นชาที่มีชื่อเสียงระดับโลกในนาม \'พระโพธิสัตว์เหล็ก\''),
  'shanghai/pearl': ('หอไข่มุกตะวันออก', 'หอคอยที่มีรูปทรงโดดเด่นด้วยลูกบอลสีชมพูตั้งตระหง่านอยู่ริมแม่น้ำหวงผู่ ถือเป็นสัญลักษณ์ของเซี่ยงไฮ้ยุคใหม่'),
  'shanghai/bund': ('เดอะบันด์', 'ย่านริมน้ำที่มีอาคารสถาปัตยกรรมเก่าแก่และโรงแรมหรูสะท้อนให้เห็นถึงความรุ่งเรืองของเซี่ยงไฮ้ในอดีต'),
  'shanghai/garden': ('สวนอวี้หยวน', 'สวนสไตล์จีนดั้งเดิมจากสมัยราชวงศ์หมิงที่เต็มไปด้วยโขดหินและสระน้ำ เปรียบเสมือนโอเอซิสใจกลางเมือง'),
  'shanghai/xlb': ('เสี่ยวหลงเปา', 'ซาลาเปาลูกเล็กที่อัดแน่นด้วยน้ำซุปร้อนๆ ถือเป็นเมนูเด็ดที่เป็นหัวใจสำคัญของอาหารเช้าแบบเซี่ยงไฮ้'),
  'hangzhou/lake': ('ทะเลสาบซีหู', 'ทะเลสาบแห่งนี้เต็มไปด้วยทิวทัศน์ของต้นหลิว เกาะน้อยใหญ่ และสะพานโค้ง ซึ่งได้รับการยกย่องในบทกวีจีนมากที่สุด'),
  'hangzhou/tea': ('ชาหลงจิ่ง', 'ชาเขียวหลงจิ่งที่ปลูกบนเนินเขาโดยรอบทะเลสาบถือเป็นชาที่มีชื่อเสียงที่สุดของประเทศจีน'),
  'hangzhou/temple': ('วัดหลิงอิ่น', 'วัดเก่าแก่ที่มีอายุกว่า 1,700 ปีแห่งนี้มีชื่อเสียงโด่งดังจากงานแกะสลักหินและพระพุทธรูปองค์ใหญ่'),
  'hangzhou/silk': ('เมืองผ้าไหม', 'ผ้าไหมหางโจวมีการทอมายาวนานนับพันปีและเป็นแหล่งความมั่งคั่งที่สำคัญของเส้นทางสายไหมในฝั่งตะวันออก'),
  'chongqing/hongya': ('ถ้ำหงหยา', 'กลุ่มอาคารบ้านเรือนบนเสาเข็มที่เกาะอยู่ริมหน้าผาแห่งนี้จะส่องแสงระยิบระยับราวกับเมืองในเทพนิยายยามค่ำคืน'),
  'chongqing/hotpot': ('หม่าล่าหม้อไฟฉงชิ่ง', 'หม้อไฟที่เดือดพล่านด้วยน้ำมันเผ็ดร้อนและพริกหอมชาคือจิตวิญญาณอันร้อนแรงของเมืองแห่งขุนเขาแห่งนี้'),
  'chongqing/monorail': ('รถไฟรางเดี่ยวฉงชิ่ง', 'รถไฟที่วิ่งทะลุผ่านตัวอาคารเป็นภาพจำอันเป็นเอกลักษณ์ของเมืองที่สร้างขึ้นบนภูเขาแห่งนี้'),
  'chongqing/river': ('ช่องเขาแยงซี', 'ท่าเรือแห่งนี้เป็นจุดเริ่มต้นของการล่องเรือชมช่องเขาแยงซี ซึ่งเป็นจุดที่เมืองตั้งตระหง่านอยู่ตรงจุดบรรจบของแม่น้ำสองสาย'),
  'dalian/square': ('จัตุรัสซิงไห่', 'จัตุรัสกลางเมืองที่ใหญ่ที่สุดในเอเชียแห่งนี้เป็นสถานที่จัดงานเทศกาลและการแสดงต่างๆ ริมชายฝั่งทะเล'),
  'dalian/beach': ('ชายหาดต้าเหลียน', 'ด้วยเวิ้งอ่าวหินและอากาศที่เย็นสบายในฤดูร้อน ต้าเหลียนจึงเป็นเมืองตากอากาศริมทะเลที่ได้รับความนิยมมากที่สุดในภาคเหนือ'),
  'dalian/football': ('เมืองแห่งฟุตบอล', 'ต้าเหลียนเปรียบเสมือนแหล่งกำเนิดฟุตบอลของจีนและเป็นที่ตั้งของสโมสรที่ประสบความสำเร็จมากที่สุดในประเทศ'),
  'dalian/seafood': ('อาหารทะเล', 'หอยเชลล์ กุ้ง และหอยเม่นจากทะเลเหลืองที่เย็นจัดเป็นวัตถุดิบชั้นเลิศที่มักปรากฏอยู่บนโต๊ะอาหารของเมืองนี้'),
  'shenyang/palace': ('พระราชวังมุกเดน', 'พระราชวังแห่งแรกของราชวงศ์ชิง ซึ่งเปรียบเสมือนน้องชายของพระราชวังต้องห้ามในกรุงปักกิ่ง'),
  'shenyang/tomb': ('สุสานราชวงศ์ชิง', 'สุสานทางทิศตะวันออกและทิศเหนือที่ล้อมรอบเมืองเป็นที่ฝังพระศพอันยิ่งใหญ่ของเหล่าผู้ก่อตั้งราชวงศ์'),
  'shenyang/factory': ('แหล่งกำเนิดอุตสาหกรรมหนัก', 'อุตสาหกรรมหนักของจีนเริ่มต้นขึ้นที่นี่ โดยมีโรงงานขนาดใหญ่มากมายจนได้รับฉายาว่าเป็นรูห์รแห่งตะวันออก'),
  'shenyang/dumpling': ('เกี๊ยวเหล่าเปียน', 'เกี๊ยวนึ่งสูตรเหล่าเปียนที่มีประวัติยาวนานกว่าสองร้อยปีถือเป็นเมนูขึ้นชื่อของชาวจีนภาคเหนือ'),
  'hefei/judge': ('ศาลท่านเปา', 'เปาบุ้นจิ้นผู้เป็นสัญลักษณ์แห่งความยุติธรรมถือกำเนิดที่นี่ ศาลแห่งนี้จึงเป็นสถานที่ที่แสดงถึงความซื่อสัตย์สุจริต'),
  'hefei/science': ('เมืองแห่งวิทยาศาสตร์', 'ศูนย์กลางด้านเทคโนโลยีที่รวบรวมมหาวิทยาลัยและห้องปฏิบัติการชั้นนำของจีนไว้มากมาย'),
  'hefei/lake': ('ทะเลสาบเฉาหู', 'หนึ่งในห้าทะเลสาบน้ำจืดที่ใหญ่ที่สุดของจีน ซึ่งมีชื่อเสียงในเรื่องปลาขาวและปู'),
  'hefei/cake': ('ขนมงาหลูโจว', 'ขนมงาสอดไส้รสหวานเป็นของว่างดั้งเดิมที่อยู่คู่กับเมืองหลูโจวมาอย่างยาวนาน'),
  'foshan/wingchun': ('มวยหย่งชุน', 'เมืองแห่งนี้เป็นต้นกำเนิดของมวยหย่งชุน ซึ่งเป็นรากฐานวิชาการต่อสู้ของยิปมันและบรูซ ลี'),
  'foshan/lion': ('เชิดสิงโต', 'เมืองหลวงแห่งการเชิดสิงโตภาคใต้ที่เต็มไปด้วยสีสันตระการตาจากการแสดงกระโดดเสาดอกเหมย'),
  'foshan/ceramic': ('เครื่องปั้นดินเผาฉือวาน', 'เตาเผาโบราณอายุนับพันปียังคงผลิตตุ๊กตาดินเผาฉือวานที่มีเอกลักษณ์และดูมีชีวิตชีวา'),
  'foshan/opera': ('งิ้วกวางตุ้ง', 'ศิลปะการแสดงบนเวทีที่เป็นที่รักที่สุดของชาวจีนภาคใต้ได้เติบโตและรุ่งเรืองขึ้นบนแผ่นดินแห่งนี้'),
  'guiyang/pavilion': ('หอเจี่ยซิ่ว', 'หอคอยสามชั้นริมแม่น้ำหนานหมิงแห่งนี้เป็นสัญลักษณ์คู่บ้านคู่เมืองกุ้ยหยางมานานกว่า 400 ปี'),
  'guiyang/sourfish': ('ต้มปลาซุปเปรี้ยว', 'เมนูขึ้นชื่อของกุ้ยโจวที่นำปลาไปต้มในน้ำซุปสีแดงรสเปรี้ยวจากมะเขือเทศหมัก'),
  'guiyang/waterfall': ('น้ำตกหวงกั่วซู่', 'หนึ่งในน้ำตกที่ใหญ่ที่สุดของเอเชียที่ไหลลงมาอย่างทรงพลังจนเกิดเป็นสายรุ้งสวยงาม'),
  'guiyang/miao': ('วัฒนธรรมชาวม้ง', 'เทศกาลและงานปักผ้าของชาวม้งผู้สวมเครื่องประดับเงินสร้างสีสันให้กับหมู่บ้านบนภูเขา'),
  'changchun/film': ('เมืองแห่งภาพยนตร์', 'สถานที่ตั้งของสตูดิโอที่เป็นจุดกำเนิดภาพยนตร์จีน จนได้รับฉายาว่าเป็นฮอลลีวูดแห่งตะวันออก'),
  'changchun/car': ('เมืองแห่งยานยนต์', 'เมืองหลวงแห่งอุตสาหกรรมรถยนต์ของจีนที่เป็นจุดเริ่มต้นของการผลิตรถยนต์ที่สร้างขึ้นเองภายในประเทศ'),
  'changchun/palace': ('พระราชวังหุ่นเชิด', 'พระราชวังแห่งนี้เป็นที่ประทับของจักรพรรดิองค์สุดท้ายและเป็นประจักษ์พยานเงียบงันต่อประวัติศาสตร์อันผันผวน'),
  'changchun/snow': ('หิมะฤดูหนาว', 'ในช่วงฤดูหนาวอันยาวนาน เมืองทั้งเมืองจะส่องประกายไปด้วยประติมากรรมน้ำแข็งและลานสกี'),
  'xining/lake': ('ทะเลสาบชิงไห่', 'ทะเลสาบน้ำเค็มที่ใหญ่ที่สุดในจีนแห่งนี้มีชื่อเสียงจากทุ่งดอกเรปซีดสีเหลืองอร่ามที่ล้อมรอบในช่วงฤดูร้อน'),
  'xining/monastery': ('วัดคุมบุม', 'หนึ่งในหกวัดที่ยิ่งใหญ่ที่สุดของพุทธศาสนาแบบทิเบต ซึ่งมีชื่อเสียงโด่งดังจากการแกะสลักเนยจามรี'),
  'xining/flower': ('ดอกเรปซีด', 'ในเดือนกรกฎาคม ที่ราบสูงแห่งนี้จะถูกปกคลุมไปด้วยทุ่งดอกเรปซีดสีทองสุดลูกหูลูกตา'),
  'xining/lamb': ('เนื้อจามรีและเนื้อแกะ', 'บะหมี่ดึงมือและเนื้อแกะย่างสไตล์ชาวหุยและชาวทิเบตคือรสชาติที่เป็นเอกลักษณ์ของที่ราบสูงแห่งนี้'),
  'guilin/karst': ('เขาหินปูนแม่น้ำหลี', 'ยอดเขาหินปูนที่โผล่พ้นสายหมอกคือทิวทัศน์ที่ปรากฏอยู่บนธนบัตรใบละ 20 หยวน'),
  'guilin/elephant': ('เขางวงช้าง', 'โขดหินรูปร่างคล้ายช้างที่กำลังหย่อนงวงลงในแม่น้ำคือสัญลักษณ์อันเป็นที่รักของเมืองนี้'),
  'guilin/terrace': ('นาขั้นบันไดหลงจี๋', 'นาขั้นบันไดสันหลังมังกรที่โอบล้อมไหล่เขาเปรียบเสมือนบันไดที่สร้างขึ้นจากหยาดเหงื่อแรงงานนับศตวรรษ'),
  'guilin/osmanthus': ('ดอกหอมหมื่นลี้', 'ชื่อของเมืองมีความหมายว่าป่าหอมหมื่นลี้ ในช่วงฤดูใบไม้ร่วงเมืองทั้งเมืองจะอบอวลไปด้วยกลิ่นหอมหวานของดอกไม้ชนิดนี้'),
  'wenzhou/merchant': ('จิตวิญญาณนักธุรกิจ', 'ผู้ประกอบการชาวเวินโจวได้รับฉายาว่าเป็นชาวยิวแห่งเมืองจีน โดยพวกเขาสร้างเครือข่ายธุรกิจไปทั่วโลก'),
  'wenzhou/shoe': ('รองเท้าและเครื่องหนัง', 'รองเท้าหนังจำนวนมหาศาลที่ใช้กันทั่วโลกล้วนผลิตมาจากเมืองแห่งโรงงานอุตสาหกรรมแห่งนี้'),
  'wenzhou/mountain': ('เขาเหยียนตั่ง', 'ด้วยชื่อเสียงด้านน้ำตกและยอดเขาที่แหลมคม ที่นี่จึงได้รับการยกย่องว่าเป็นภูเขาแห่งแรกริมทะเล'),
  'wenzhou/seafood': ('อาหารทะเล', 'ปลาหมึก หอยเชลล์ และปลาจากทะเลจีนตะวันออกคือวัตถุดิบหลักบนโต๊ะอาหารของชาวเมือง'),
  'tangshan/memorial': ('อนุสรณ์สถานแผ่นดินไหว', 'สวนอนุสรณ์สถานเหตุการณ์แผ่นดินไหวครั้งใหญ่ในปี ค.ศ. 1976 คือสัญลักษณ์ของการเกิดใหม่ของเมือง'),
  'tangshan/coal': ('ถ่านหินและเหล็กกล้า', 'ที่นี่เป็นจุดกำเนิดอุตสาหกรรมสมัยใหม่ของจีน โดยเป็นที่ตั้งของเหมืองถ่านหินและทางรถไฟแห่งแรกของประเทศ'),
  'tangshan/ceramic': ('เครื่องปั้นดินเผาถังซาน', 'เมืองแห่งเครื่องลายครามทางตอนเหนือที่มีชื่อเสียงโดดเด่นในเรื่องโบนไชน่าอันประณีตงดงาม'),
  'tangshan/lake': ('สวนสาธารณะหนานหู', 'สวนสาธารณะริมทะเลสาบที่ปรับปรุงจากพื้นที่เหมืองเก่าจนกลายเป็นปอดสีเขียวของเมือง'),
  'anshan/steel': ('เมืองเหล็กกล้า', 'เมืองที่เป็นฐานการผลิตเหล็กกล้าที่ใหญ่ที่สุดของจีนจนได้รับฉายาว่าเป็นเมืองหลวงแห่งเหล็กกล้าของประเทศ'),
  'anshan/jade': ('หยกซิ่วเหยียน', 'เมืองที่เป็นแหล่งหยกอันดับหนึ่งของจีนและเป็นที่ตั้งของงานแกะสลักหยกที่ใหญ่ที่สุดในโลก'),
  'anshan/mountain': ('เขาเชียนซาน', 'ยอดเขาศักดิ์สิทธิ์ทางตอนเหนือที่เต็มไปด้วยวัดวาอารามและทิวทัศน์ของยอดเขาที่สวยงามดั่งดอกบัวพันกลีบ'),
  'anshan/spring': ('น้ำพุร้อนถังกังจื่อ', 'แหล่งน้ำพุร้อนเพื่อการบำบัดที่มีประวัติยาวนานนับพันปีและเคยเป็นสถานที่พักผ่อนของเหล่าจักรพรรดิในอดีต'),
  'linyi/market': ('ตลาดค้าส่งหลินอี๋', 'ศูนย์กลางการค้าส่งที่ใหญ่ที่สุดในภาคเหนือของจีนซึ่งเป็นจุดกระจายสินค้าไปทั่วประเทศ'),
  'linyi/brush': ('บ้านเกิดปรมาจารย์พู่กัน', 'เมืองแห่งศิลปะการเขียนพู่กันและเป็นบ้านเกิดของหวังซีจือ ปรมาจารย์ด้านอักษรศิลป์ผู้ยิ่งใหญ่ของจีน'),
  'linyi/mountain': ('เขาเหมิงซาน', 'ภูเขาที่สูงเป็นอันดับสองของมณฑลซานตง ซึ่งเปรียบเสมือนแหล่งผลิตอากาศบริสุทธิ์ที่เต็มไปด้วยน้ำตกสวยงาม'),
  'linyi/pancake': ('แพนเค้กอี๋เหมิง', 'เจียนปิ่งหรือแพนเค้กแผ่นบางที่ทำจากข้าวโพด ซึ่งเป็นอาหารหลักดั้งเดิมของชาวเขาอี๋เหมิง'),
  'cangzhou/lion': ('สิงโตเหล็ก', 'รูปปั้นสิงโตเหล็กหล่อขนาดมหึมาที่มีอายุกว่า 1,100 ปี ซึ่งถือเป็นสัญลักษณ์อันภาคภูมิใจของเมือง'),
  'cangzhou/martial': ('ศิลปะการต่อสู้', 'เมืองที่ได้ชื่อว่าเป็นบ้านแห่งวูซู ซึ่งเป็นแหล่งกำเนิดของปรมาจารย์และสำนักศิลปะการต่อสู้ที่มีชื่อเสียง'),
  'cangzhou/canal': ('คลองขุดต้ายวิ่นเหอ', 'คลองปักกิ่ง-หางโจวที่ไหลผ่านตัวเมือง โดยยังคงหลงเหลือร่องรอยของท่าเรือเก่าแก่ให้เห็นจนถึงปัจจุบัน'),
  'cangzhou/jujube': ('พุทราทองคำ', 'พุทราสายพันธุ์ที่มีเปลือกบางและรสหวานฉ่ำ ซึ่งได้รับการยกย่องว่าเป็นราชาแห่งผลไม้อบแห้ง'),
  'nantong/textile': ('เมืองแห่งสิ่งทอ', 'เมืองหลวงแห่งสิ่งทอของจีนที่ส่งออกผ้าฝ้ายคุณภาพเยี่ยมไปจำหน่ายทั่วโลก'),
  'nantong/mountain': ('เขาหลางซาน', 'ภูเขาศักดิ์สิทธิ์ห้ายอดที่ตั้งตระหง่านอยู่บริเวณปากแม่น้ำแยงซี เป็นจุดหมายปลายทางยอดนิยมของผู้แสวงบุญและนักท่องเที่ยว'),
  'nantong/kite': ('ว่าวนกหวีด', 'ว่าวปั้นเหยาที่มีการติดตั้งนกหวีดเพื่อให้เกิดเสียงหึ่งๆ ขณะลอยอยู่บนฟ้าเป็นงานฝีมือดั้งเดิมของเมืองนี้'),
  'nantong/school': ('ต้นกำเนิดการศึกษาแผนใหม่', 'จางเจียน นักอุตสาหกรรมผู้มีชื่อเสียงได้ก่อตั้งโรงเรียนและพิพิธภัณฑ์สมัยใหม่แห่งแรกของจีนขึ้นที่นี่'),
  'taizhou/opera': ('เหมยหลานฟาง', 'เมืองนี้เป็นบ้านเกิดของเหมยหลานฟาง ปรมาจารย์ผู้เป็นตำนานแห่งงิ้วปักกิ่ง'),
  'taizhou/tea': ('น้ำชายามเช้า', 'วัฒนธรรมการรับประทานอาหารเช้าด้วยซาลาเปาและน้ำชาถือเป็นกิจวัตรประจำวันอันเป็นเอกลักษณ์ของชาวเมือง'),
  'taizhou/boat': ('เทศกาลเรือฉินถง', 'เทศกาลแข่งเรือที่เต็มไปด้วยฝีพายหลายร้อยคนในช่วงฤดูใบไม้ผลิช่วยปลุกแม่น้ำให้กลับมามีชีวิตชีวาอีกครั้ง'),
  'taizhou/meatball': ('หมูสับหัวสิงโต', 'เมนูหมูสับก้อนโตเนื้อนุ่มที่เรียกว่าหัวสิงโตเป็นอาหารขึ้นชื่อระดับตำนานของอาหารสไตล์หวยหยาง'),
  'jinhua/ham': ('แฮมจินหัว', 'แฮมสีแดงที่ผ่านกรรมวิธีการบ่มแบบดั้งเดิมมานานหลายศตวรรษและถือว่ามีชื่อเสียงที่สุดในประเทศจีน'),
  'jinhua/film': ('สตูดิโอเหิงเตี้ยน', 'กองถ่ายภาพยนตร์กลางแจ้งที่ใหญ่ที่สุดในโลกซึ่งเป็นสถานที่ถ่ายทำละครย้อนยุคจำนวนนับไม่ถ้วน'),
  'jinhua/cave': ('ถ้ำซวงหลง', 'ถ้ำใต้ดินที่ต้องนั่งเรือลอดผ่านช่องหินเตี้ยๆ เข้าไป ซึ่งความงดงามภายในจะทำให้คุณต้องตะลึง'),
  'jinhua/bridge': ('สะพานโบราณ', 'สะพานหินโค้งและเมืองริมน้ำที่สะท้อนถึงความงดงามตามแบบฉบับของภูมิภาคเจียงหนาน'),
  'wuhu/park': ('สวนสนุกฟางเท่อ', 'หนึ่งในสวนสนุกที่ใหญ่ที่สุดของจีนที่พร้อมมอบความสนุกสนานตื่นเต้นให้กับทุกคนในครอบครัว'),
  'wuhu/ironart': ('ภาพวาดเหล็ก', 'งานศิลปะภาพวาดเหล็กอันวิจิตรบรรจงที่ทำจากการดัดเหล็กเป็นงานฝีมือที่มีประวัติยาวนานกว่า 300 ปี'),
  'wuhu/rice': ('ท่าเรือข้าว', 'เมืองริมแม่น้ำแยงซีแห่งนี้เคยเป็นตลาดค้าข้าวที่ใหญ่ที่สุดของจีนในอดีต'),
  'wuhu/river': ('ท่าเรือแม่น้ำแยงซี', 'ท่าเรือที่คึกคักแห่งนี้เปรียบเสมือนประตูสู่ทะเลของมณฑลอันฮุย'),
  'huangshan/peak': ('ภูเขาหวงซาน', 'ภูเขาที่มีชื่อเสียงที่สุดของจีน โดดเด่นด้วยยอดเขาหินแกรนิต ทะเลหมอก และต้นสนรูปร่างแปลกตา'),
  'huangshan/village': ('หมู่บ้านหงชุน', 'หมู่บ้านสถาปัตยกรรมแบบฮุยที่มีกำแพงสีขาวและทางน้ำไหลผ่าน ได้รับการขึ้นทะเบียนเป็นมรดกโลกและงดงามราวกับภาพวาด'),
  'huangshan/tea': ('ชาเหมาเฟิง', 'ชาเขียวปลายยอดอ่อนที่เก็บเกี่ยวจากบนภูเขาที่มีหมอกปกคลุม และเป็นหนึ่งในสิบสุดยอดชาที่มีชื่อเสียงที่สุดของจีน'),
  'huangshan/ink': ('หมึกและศิลปะหุยโจว', 'หมึกจีน งานแกะสลักไม้ และศิลปะการเขียนพู่กันจีนถือเป็นสมบัติทางวัฒนธรรมอันล้ำค่าของภูมิภาคนี้'),
  'yichun/moon': ('ภูเขาหมิงเยว่', 'ภูเขาแห่งพระจันทร์สว่างที่มีชื่อเสียงในเรื่องบ่อน้ำพุร้อนและทิวทัศน์สวยงามจากการนั่งกระเช้าไฟฟ้า'),
  'yichun/spring': ('บ่อน้ำพุร้อน', 'น้ำพุร้อนที่อุดมไปด้วยแร่ธาตุซีลีเนียมหายาก ทำให้เมืองนี้กลายเป็นศูนย์กลางการแช่น้ำพุร้อนของจีน'),
  'yichun/zen': ('พุทธศาสนานิกายฉาน', 'วัดบนภูเขาที่เป็นรากฐานของนิกายฉานในจีน เชิญชวนให้ผู้มาเยือนได้สัมผัสกับความสงบทางจิตใจ'),
  'yichun/rice': ('ที่ราบลุ่มแม่น้ำหยวนเหอ', 'ที่ราบอันอุดมสมบูรณ์แห่งนี้เป็นแหล่งเพาะปลูกข้าวที่สำคัญของมณฑลเจียงซีมาอย่างยาวนาน'),
  'zhangzhou/narcissus': ('ดอกนาร์ซิสซัส', 'แหล่งปลูกหัวดอกนาร์ซิสซัสที่มีชื่อเสียงที่สุดของจีน ซึ่งถือเป็นสัญลักษณ์แห่งเทศกาลฤดูใบไม้ผลิ'),
  'zhangzhou/tulou': ('บ้านดินถู่โหลว', 'ป้อมปราการดินอัดทรงกลมขนาดใหญ่ที่ได้รับการขึ้นทะเบียนเป็นมรดกโลก โดยเป็นที่อยู่อาศัยของคนทั้งหมู่บ้านภายใต้หลังคาเดียวกัน'),
  'zhangzhou/banana': ('ผลไม้เมืองร้อน', 'สวนกล้วย ลำไย และส้มเขียวหวาน ทำให้พื้นที่สามเหลี่ยมปากแม่น้ำแห่งนี้เขียวขจีตลอดทั้งปี'),
  'zhangzhou/coast': ('เกาะตงซาน', 'เกาะที่เป็นดั่งไข่มุกแห่งชายฝั่งทางใต้ โดดเด่นด้วยหาดทรายสีทองและหมู่บ้านชาวประมง'),
  'guangzhou/tower': ('หอกวางโจว', 'หอคอยที่สูงที่สุดแห่งหนึ่งของโลกซึ่งมีรูปทรงเพรียวบางและประดับประดาด้วยแสงสีเปลี่ยนไปมาในยามค่ำคืน'),
  'guangzhou/dimsum': ('ติ่มซำ', 'วัฒนธรรมการดื่มชาและทานติ่มซำในเข่งไม้ไผ่ถือเป็นหัวใจสำคัญของการรับประทานอาหารแบบกวางตุ้ง'),
  'guangzhou/academy': ('ศาลบรรพชนตระกูลเฉิน', 'หอประชุมตระกูลแห่งนี้เป็นผลงานชิ้นเอกของงานฝีมือชาวกวางตุ้ง โดดเด่นด้วยงานแกะสลักไม้และภาพปูนปั้นอันวิจิตรบรรจง'),
  'guangzhou/flower': ('นครแห่งดอกไม้', 'กวางโจวได้รับฉายาว่านครแห่งดอกไม้ เพราะมีดอกไม้บานสะพรั่งตลอดทั้งปีและมีการจัดงานเทศกาลดอกไม้อย่างยิ่งใหญ่ในช่วงเทศกาลตรุษจีน'),
  'wuhan/crane': ('หอกระเรียนเหลือง', 'หอคอยเก่าแก่พันปีที่ตั้งตระหง่านอยู่ริมแม่น้ำแยงซีแห่งนี้ เป็นแรงบันดาลใจให้แก่บทกวีจีนที่มีชื่อเสียงมากมาย'),
  'wuhan/noodle': ('บะหมี่แห้งร้อน', 'บะหมี่แห้งคลุกซอสงาเป็นเมนูอาหารเช้าที่ขาดไม่ได้ของชาวอู่ฮั่น'),
  'wuhan/duckneck': ('คอเป็ดพะโล้รสเผ็ด', 'คอเป็ดพะโล้รสจัดจ้านเป็นของว่างยอดนิยมที่ชาวเมืองมักซื้อมาทานคู่กับการพูดคุยยามค่ำคืน'),
  'wuhan/university': ('ซากุระมหาวิทยาลัยอู่ฮั่น', 'ในช่วงฤดูใบไม้ผลิ ดอกซากุระที่บานสะพรั่งภายในมหาวิทยาลัยอู่ฮั่นจะดึงดูดนักท่องเที่ยวหลายพันคนให้มาเยี่ยมชม'),
  'tianjin/eye': ('เทียนจินอาย', 'ชิงช้าสวรรค์ที่สร้างขึ้นบนสะพานแห่งนี้ช่วยให้คุณมองเห็นทิวทัศน์ของแม่น้ำทั้งสองฝั่งได้ในคราวเดียว'),
  'tianjin/baozi': ('ซาลาเปาโกวปู้หลี่', 'ซาลาเปาไส้หมูจีบสวยที่เป็นเมนูขึ้นชื่อประจำเมืองมานานกว่า 150 ปี'),
  'tianjin/crosstalk': ('เซี่ยงเซิง', 'ศิลปะการแสดงตลกพูดคุยสองคนที่เป็นวัฒนธรรมดั้งเดิมของเทียนจิน ซึ่งมีต้นกำเนิดมาจากโรงน้ำชา'),
  'tianjin/architecture': ('ย่านสถาปัตยกรรมยุโรป', 'กลุ่มวิลล่าสไตล์ยุโรปในย่านถนนสายหลักทั้งห้าทำให้เทียนจินได้รับฉายาว่าเป็นพิพิธภัณฑ์สถาปัตยกรรมกลางแจ้ง'),
  'xiamen/island': ('เกาะกูลั่งอวี่', 'เกาะที่ได้รับการขึ้นทะเบียนเป็นมรดกโลกแห่งนี้เป็นพิพิธภัณฑ์กลางแจ้งที่เต็มไปด้วยวิลล่าสไตล์โคโลเนียลและถนนที่ห้ามรถยนต์วิ่ง'),
  'xiamen/piano': ('เกาะเปียโน', 'เกาะกูลั่งอวี่ได้รับฉายาว่าเกาะเปียโน เนื่องจากเป็นสถานที่ที่มีจำนวนเปียโนต่อประชากรสูงที่สุดแห่งหนึ่ง'),
  'xiamen/egret': ('นกยางขาว', 'นกยางขาวเป็นสัญลักษณ์ประจำเมืองที่ชวนให้นึกถึงชื่อเดิมของเมืองนี้ที่เรียกว่าเกาะนกยาง'),
  'xiamen/oyster': ('หอยทอด', 'หอยนางรมสดทอดกับไข่จนกรอบนอกนุ่มในเป็นเมนูเด็ดประจำท้องถิ่นริมทะเล'),
  'harbin/ice': ('เทศกาลน้ำแข็ง', 'เทศกาลฤดูหนาวที่มีการจัดแสดงปราสาทน้ำแข็งขนาดมหึมาประดับไฟสวยงาม ซึ่งถือเป็นงานที่ใหญ่ที่สุดในโลก'),
  'harbin/cathedral': ('มหาวิหารเซนต์โซเฟีย', 'มหาวิหารนิกายออร์ทอดอกซ์ที่มีโดมรูปหัวหอมแห่งนี้เป็นสัญลักษณ์ที่สะท้อนถึงอดีตอันรุ่งเรืองในแบบยุโรปของเมืองฮาร์บิน'),
  'harbin/sausage': ('ไส้กรอกแดง', 'ไส้กรอกรมควันสไตล์รัสเซียสีแดงสดเป็นอาหารขึ้นชื่อที่มีประวัติศาสตร์ยาวนานกว่าร้อยปีของเมืองนี้'),
  'harbin/accordion': ('เมืองแห่งดนตรี', 'ด้วยมรดกทางวัฒนธรรมที่ได้รับอิทธิพลจากรัสเซีย ฮาร์บินจึงเป็นเมืองที่ก่อตั้งวงซิมโฟนีออร์เคสตราวงแรกของจีน'),
  'fuzhou/alley': ('ซานฟางชีเซี่ยง', 'ย่านเมืองเก่าที่มีกำแพงสีขาวและหลังคากระเบื้องสีดำแห่งนี้เปรียบเสมือนพิพิธภัณฑ์ที่มีชีวิตซึ่งรวบรวมสถาปัตยกรรมสมัยราชวงศ์หมิงและชิงไว้'),
  'fuzhou/banyan': ('เมืองแห่งต้นไทร', 'ต้นไทรยักษ์โบราณที่แผ่กิ่งก้านให้ร่มเงาไปทั่วถนนทำให้ฝูโจวได้รับฉายาว่าเป็นเมืองแห่งต้นไทร'),
  'fuzhou/hotspring': ('บ่อน้ำพุร้อน', 'น้ำพุร้อนที่ผุดขึ้นมากลางใจเมืองฝูโจวถูกนำมาใช้ในโรงอาบน้ำสาธารณะมานานนับพันปี'),
  'fuzhou/soup': ('พระกระโดดกำแพง', 'ซุปเลิศรสที่เคี่ยวจากวัตถุดิบชั้นเลิศหลายสิบชนิดนี้ถือเป็นสุดยอดเมนูอาหารที่เป็นหน้าเป็นตาของมณฑลฝูเจี้ยน'),
  'dongguan/robot': ('โรงงานของโลก', 'ตงกวนเป็นฐานการผลิตอุปกรณ์อิเล็กทรอนิกส์รายใหญ่ของโลกด้วยเทคโนโลยีโรงงานอัตโนมัติที่ทันสมัย'),
  'dongguan/basketball': ('เมืองแห่งบาสเกตบอล', 'ตงกวนเป็นที่ตั้งของสโมสรบาสเกตบอลที่ประสบความสำเร็จมากที่สุดในประเทศจีนจนได้รับฉายาว่าเป็นเมืองแห่งบาสเกตบอล'),
  'dongguan/keyuan': ('สวนเข่อหยวน', 'หนึ่งในสี่สวนคลาสสิกที่มีชื่อเสียงที่สุดของมณฑลกวางตุ้ง ซึ่งโดดเด่นด้วยความงดงามของสระน้ำและศาลาพักผ่อน'),
  'dongguan/cannon': ('ป้อมปราการหู่เหมิน', 'ป้อมปราการหู่เหมินเป็นสถานที่ทางประวัติศาสตร์ที่เคยเป็นจุดเริ่มต้นของสงครามฝิ่นและเป็นจุดที่เคยมีการทำลายฝิ่นทิ้ง'),
  'lanzhou/beefnoodle': ('บะหมี่เนื้อหลานโจว', 'ด้วยน้ำซุปเนื้อรสกลมกล่อมและเส้นบะหมี่ที่นวดด้วยมือ ทำให้หลานโจวได้รับการยกย่องว่าเป็นเมืองหลวงแห่งบะหมี่ของจีน'),
  'lanzhou/waterwheel': ('กังหันน้ำ', 'กังหันน้ำขนาดใหญ่ริมแม่น้ำเหลืองเป็นสัญลักษณ์ที่แสดงถึงภูมิปัญญาด้านวิศวกรรมชลประทานที่มีมานานหลายศตวรรษ'),
  'lanzhou/statue': ('อนุสาวรีย์มารดาแม่น้ำเหลือง', 'รูปปั้นแม่และลูกที่ตั้งอยู่ริมฝั่งแม่น้ำเป็นตัวแทนของแม่น้ำเหลืองซึ่งเป็นสายน้ำที่หล่อเลี้ยงอารยธรรมจีนมาอย่างยาวนาน'),
  'lanzhou/raft': ('แพหนังแกะ', 'แพแบบดั้งเดิมที่ทำจากหนังแกะพองลมยังคงถูกนำมาใช้ล่องไปตามแม่น้ำเหลืองจนถึงปัจจุบัน'),
  'urumqi/bazaar': ('ตลาดแกรนด์บาซาร์', 'ตลาดแห่งนี้เต็มไปด้วยหอคอยสูงและร้านขายเครื่องเทศที่สะท้อนสีสันแห่งเส้นทางสายไหม'),
  'urumqi/tianshan': ('ทะเลสาบเทียนฉือ', 'ทะเลสาบเทียนฉือตั้งอยู่ใต้เทือกเขาหิมะเทียนซานและรายล้อมไปด้วยป่าสนอันร่มรื่น'),
  'urumqi/kebab': ('เนื้อแกะย่าง', 'เนื้อแกะเสียบไม้ย่างบนเตาถ่านเป็นเมนูสำคัญที่ขาดไม่ได้บนโต๊ะอาหารของชาวอุยกูร์'),
  'urumqi/dance': ('ระบำอุยกูร์', 'การร่ายรำหมุนตัวของชาวอุยกูร์ประกอบเสียงกลองและเครื่องดนตรีราวัปช่วยสร้างสีสันให้กับทุกงานเฉลิมฉลอง'),
  'haikou/coconut': ('เมืองแห่งมะพร้าว', 'ถนนหนทางที่เรียงรายไปด้วยต้นมะพร้าวทำให้ไหโข่วได้รับฉายาว่าเป็นเมืองแห่งมะพร้าว'),
  'haikou/arcade': ('ย่านตึกแถวฉีโหลว', 'อาคารสถาปัตยกรรมแบบฉีโหลวที่มีทางเดินใต้ถุนตึกช่วยสร้างบรรยากาศถนนคนเดินที่ร่มรื่น'),
  'haikou/crater': ('อุทยานภูเขาไฟ', 'ปากปล่องภูเขาไฟที่ดับแล้วกลายเป็นอุทยานธรณีวิทยาอันเขียวขจีบริเวณชานเมือง'),
  'haikou/turtle': ('ทะเลเขตร้อน', 'น้ำทะเลที่ใสสะอาดและแนวปะการังทำให้ชายฝั่งแห่งนี้เป็นบ้านของเต่าทะเล'),
  'luoyang/grotto': ('ถ้ำหินหลงเหมิน', 'พระพุทธรูปนับหมื่นองค์ที่แกะสลักบนหน้าผาถือเป็นสมบัติทางศิลปะระดับโลกที่ได้รับการขึ้นทะเบียนเป็นมรดกโลก'),
  'luoyang/peony': ('เมืองหลวงแห่งดอกโบตั๋น', 'ดอกโบตั๋นนับพันต้นที่บานสะพรั่งในเดือนเมษายนทำให้ลั่วหยางได้ชื่อว่าเป็นเมืองหลวงแห่งดอกโบตั๋น'),
  'luoyang/whitehorse': ('วัดม้าขาว', 'วัดแห่งนี้ก่อตั้งขึ้นในปี ค.ศ. 68 และได้รับการยกย่องว่าเป็นวัดพุทธแห่งแรกของจีน'),
  'luoyang/capital': ('เมืองหลวงเก่า', 'ลั่วหยางเคยเป็นเมืองหลวงของ 13 ราชวงศ์และถือเป็นแหล่งกำเนิดอารยธรรมจีนที่สำคัญ'),
  'shantou/gongfutea': ('ชาฉงฟู', 'การชงชาฉงฟูแบบแต้จิ๋วในถ้วยใบเล็กถือเป็นศิลปะแห่งการต้อนรับแขกเหรื่อที่ประณีต'),
  'shantou/beefpot': ('หม้อไฟเนื้อ', 'หม้อไฟสไตล์แต้จิ๋วที่ขึ้นชื่อเรื่องเนื้อวัวสดสไลด์บางซึ่งลวกเพียงไม่กี่วินาทีก็พร้อมรับประทาน'),
  'shantou/opera': ('งิ้วแต้จิ๋ว', 'งิ้วแต้จิ๋วที่มีประวัติศาสตร์ยาวนานกว่า 600 ปี โดดเด่นด้วยท่วงทำนองที่อ่อนช้อยและเครื่องแต่งกายที่ปักลวดลายอย่างวิจิตร'),
  'shantou/harbor': ('ท่าเรือซัวเถา', 'ซัวเถาเป็นบ้านเกิดของชาวจีนโพ้นทะเลจำนวนมาก และท่าเรือแห่งนี้ก็เป็นประตูการค้าทางทะเลที่เก่าแก่'),
  'baoding/mansion': ('จวนผู้ว่าการ', 'จวนผู้ว่าการแห่งนี้เป็นสำนักงานระดับสูงสุดของมณฑลในสมัยราชวงศ์ชิง และยังคงได้รับการอนุรักษ์ไว้อย่างดีในฐานะสถานที่ราชการ'),
  'baoding/donkeyburger': ('เบอร์เกอร์เนื้อลา', 'เนื้อลาปรุงรสยัดไส้ในขนมปังแบนกรอบเป็นอาหารริมทางขึ้นชื่อของภูมิภาคนี้'),
  'baoding/balls': ('ลูกเหล็กสุขภาพ', 'ลูกเหล็กสุขภาพที่หมุนในฝ่ามือเป็นประเพณีการบริหารมือที่มีมานานหลายศตวรรษ'),
  'baoding/reeds': ('หนองน้ำไป๋หยางเตี้ยน', 'หนองน้ำแห่งนี้เป็นพื้นที่ชุ่มน้ำที่ใหญ่ที่สุดทางตอนเหนือ และเป็นสวรรค์ของนกที่มีทั้งต้นกกและดอกบัว'),
  'jilin/rime': ('ปรากฏการณ์น้ำค้างแข็ง', 'ปรากฏการณ์น้ำค้างแข็งสีขาวที่ปกคลุมต้นไม้ริมแม่น้ำซงฮวาเป็นหนึ่งในสี่สิ่งมหัศจรรย์ทางธรรมชาติของจีน'),
  'jilin/snowboard': ('สกีรีสอร์ต', 'ด้วยหิมะที่หนาและฤดูที่ยาวนาน เมืองนี้จึงเป็นหนึ่งในสกีรีสอร์ตชั้นนำทางตอนเหนือ'),
  'jilin/meteorite': ('พิพิธภัณฑ์อุกกาบาต', 'อุกกาบาตหินที่ใหญ่ที่สุดในโลกซึ่งตกลงมาในปี 1976 จัดแสดงอยู่ที่นี่'),
  'jilin/skate': ('แม่น้ำซงฮวาที่กลายเป็นน้ำแข็ง', 'แม่น้ำซงฮวาที่กลายเป็นน้ำแข็งจะกลายเป็นลานสเก็ตที่เต็มไปด้วยนักสเก็ตและผู้คนเดินเล่นในฤดูหนาว'),
  'ordos/khan': ('สุสานเจงกิสข่าน', 'สุสานอันยิ่งใหญ่ที่สร้างขึ้นเพื่อเป็นเกียรติแก่วีรบุรุษแห่งทุ่งหญ้าเจงกิสข่านเป็นหัวใจของวัฒนธรรมมองโกล'),
  'ordos/cashmere': ('ผ้าแคชเมียร์', 'ผ้าแคชเมียร์ที่ทอจากขนแพะเออร์โดสทำให้เมืองนี้เป็นที่รู้จักในอุตสาหกรรมสิ่งทอระดับโลก'),
  'ordos/sanddune': ('เนินทรายร้องเพลง', 'เนินทรายขนาดยักษ์ที่ส่งเสียงหึ่งๆ เมื่อคุณไถลลงมาเป็นจุดแวะพักยอดนิยมของทะเลทรายคูบู่ฉี'),
  'ordos/yurt': ('กระโจมมองโกล', 'กระโจมผ้าสักหลาดสีขาวที่ตั้งอยู่บนทุ่งหญ้าอันกว้างใหญ่เป็นสัญลักษณ์ของชีวิตเร่ร่อน'),
  'jining/confucius': ('ศาลเจ้าขงจื๊อ', 'ในเมืองชวีฟู่ที่อยู่ใกล้เคียง ศาลเจ้า จวน และสุสานของปราชญ์ขงจื๊อได้รับการขึ้นทะเบียนเป็นมรดกโลกโดยยูเนสโก'),
  'jining/barge': ('คลองใหญ่', 'จี่หนิงเป็นเมืองท่าที่คึกคักบนคลองปักกิ่ง-หางโจว และเป็นศูนย์กลางของวัฒนธรรมคลอง'),
  'jining/sword': ('เขาเหลียงซาน', 'วีรบุรุษผู้กล้า 108 คนจากวรรณกรรมคลาสสิกเรื่อง \'ซ้องกั๋ง\' ได้รวมตัวกัน ณ เนินเขาและหนองน้ำแห่งนี้.'),
  'jining/fishnet': ('ทะเลสาบเวยซาน', 'ณ ทะเลสาบบัวที่ใหญ่ที่สุดทางตอนเหนือแห่งนี้ ชาวประมงยังคงทอดแหจับปลาด้วยวิถีดั้งเดิม.'),
  'langfang/culture': ('ศูนย์วัฒนธรรมเส้นทางสายไหม', 'ศูนย์วัฒนธรรมอันทันสมัยขนาดใหญ่ของเมืองแห่งนี้รวบรวมศิลปะจากเส้นทางสายไหมไว้ในที่เดียว.'),
  'langfang/furniture': ('เมืองเฟอร์นิเจอร์', 'เซียงเหอซึ่งเป็นเมืองใกล้เคียง ถือเป็นหนึ่งในศูนย์กลางการผลิตและค้าเฟอร์นิเจอร์ที่ใหญ่ที่สุดของจีน.'),
  'langfang/tunnel': ('อุโมงค์สงครามโบราณ', 'อุโมงค์ทางทหารใต้ดินอายุนับพันปีเหล่านี้ แสดงให้เห็นถึงแนวป้องกันชายแดนเก่าแก่.'),
  'langfang/themepark': ('สวนสนุก \'เมืองอันดับหนึ่ง\'', 'สวนสนุกขนาดใหญ่ที่จำลองเมืองโบราณมีกำแพงล้อมรอบแห่งนี้ ยินดีต้อนรับนักท่องเที่ยวทุกครอบครัว.'),
  'yancheng/salt': ('เมืองแห่งเกลือ', 'ชื่อของเมืองนี้มีความหมายว่า \'ป้อมเกลือ\' และเป็นศูนย์กลางการผลิตเกลือของจีนมานานหลายศตวรรษ.'),
  'yancheng/crane': ('นกกระเรียนมงกุฎแดง', 'พื้นที่ชุ่มน้ำชายฝั่งแห่งนี้เป็นแหล่งอาศัยในฤดูหนาวที่ใหญ่ที่สุดในโลกสำหรับนกกระเรียนมงกุฎแดงป่า.'),
  'yancheng/elk': ('กวางมิลู่', 'กวางมิลู่ที่เคยสูญพันธุ์จากธรรมชาติ ได้กลับมาแพร่พันธุ์อีกครั้งในพื้นที่ชุ่มน้ำแห่งนี้.'),
  'yancheng/wetland': ('พื้นที่ชุ่มน้ำชายฝั่ง', 'พื้นที่ราบน้ำขึ้นน้ำลงที่ได้รับการขึ้นทะเบียนจากยูเนสโกแห่งนี้ เป็นจุดแวะพักสำคัญสำหรับนกอพยพทั่วโลก.'),
  'huzhou/brush': ('พู่กันหู', 'พู่กันหู ซึ่งเป็นหนึ่งใน \'สี่สมบัติ\' ของการประดิษฐ์อักษรจีน มีการผลิตขึ้นที่นี่.'),
  'huzhou/bamboo': ('ทะเลไผ่อันจี๋', 'ป่าไผ่สีเขียวอันกว้างใหญ่ไร้ที่สิ้นสุด ซึ่งเป็นแรงบันดาลใจให้แก่ภาพยนตร์หลายเรื่อง ช่วยให้บรรยากาศเย็นสบาย.'),
  'huzhou/silkworm': ('หนอนไหม', 'ชายฝั่งทางใต้ของทะเลสาบไท่เป็นศูนย์กลางการผลิตผ้าไหมหม่อนมานานนับพันปี.'),
  'huzhou/whitetea': ('ชาขาวอันจี๋', 'ชาขาวอันจี๋ที่มีใบสีอ่อนและรสชาติหวาน ถือเป็นหนึ่งในชาที่หายากที่สุดของจีน.'),
  'quzhou/go': ('หมากล้อม', 'เมืองแห่งนี้ได้รับการยกย่องว่าเป็น \'ดินแดนแห่งหมากล้อม\' ซึ่งเป็นที่เคารพจากตำนานเขาหลานเคอ.'),
  'quzhou/peaks': ('ภูเขาเจียงหลาง', 'เสาหินยักษ์สามต้นที่ตั้งตระหง่านเสียดฟ้าเป็นภูมิทัศน์อันเป็นเอกลักษณ์ที่ได้รับการขึ้นทะเบียนจากยูเนสโก'),
  'quzhou/ponkan': ('ส้มพอนคันเมืองฉวีโจว', 'ส้มพอนคันเปลือกหวานเป็นของขวัญจากเนินเขาอันอบอุ่นในช่วงฤดูหนาว'),
  'quzhou/cake': ('ขนมปังแบนอบ', 'ขนมปังแบนกรอบโรยงาที่อบบนผนังเตาเป็นอาหารเช้าคลาสสิกของท้องถิ่น'),
  'huainan/tofu': ('ต้นกำเนิดเต้าหู้', 'เต้าหู้ถูกคิดค้นขึ้นที่ภูเขาปากงเมื่อ 2,000 ปีก่อน และแพร่หลายสู่ครัวโลกจากที่นี่'),
  'huainan/coalmine': ('เมืองถ่านหิน', 'เมืองหวยหนานอุดมไปด้วยแหล่งถ่านหิน จึงเป็นฐานพลังงานที่สำคัญของจีนตะวันออก'),
  'huainan/oldtown': ('เมืองเก่าอำเภอโช่ว', 'กำแพงเมืองสมัยราชวงศ์ซ่งที่ได้รับการอนุรักษ์ไว้อย่างสมบูรณ์เป็นตัวอย่างที่หาได้ยากของการออกแบบการป้องกันเมืองโบราณ'),
  'huainan/classic': ('คัมภีร์หวยหนานจื่อ', 'คัมภีร์ปรัชญาที่รวบรวมโดยองค์ชายหลิวอันถูกเขียนขึ้นบนผืนแผ่นดินแห่งนี้'),
  'jingdezhen/porcelain': ('เมืองหลวงแห่งเครื่องเคลือบดินเผา', 'เมืองนี้ผลิตเครื่องเคลือบดินเผาสำหรับราชสำนักมานานนับพันปี จึงได้รับการขนานนามว่าเป็น \'เมืองหลวงแห่งเครื่องเคลือบดินเผา\' ของโลก'),
  'jingdezhen/kiln': ('เตาเผาโบราณ', 'เตาเผารูปมังกรที่ใช้ไม้เป็นเชื้อเพลิงยังคงรักษาศิลปะการเผาเครื่องเคลือบดินเผาแบบดั้งเดิมไว้'),
  'jingdezhen/bluewhite': ('เครื่องเคลือบสีน้ำเงินขาว', 'เครื่องเคลือบดินเผาสีขาวที่มีลวดลายสีน้ำเงินโคบอลต์เป็นเอกลักษณ์อันโด่งดังระดับโลกของเมืองนี้'),
  'jingdezhen/painting': ('จิตรกรรมเครื่องเคลือบดินเผา', 'เครื่องเคลือบดินเผาที่วาดด้วยพู่กันละเอียดโดยช่างฝีมือชั้นครูนั้นมีคุณค่าดุจภาพวาดชั้นเลิศ'),
  'jian/jinggang': ('เทือกเขาจิ่งกัง', 'เทือกเขาที่ปกคลุมด้วยหมอกแห่งนี้เป็นฐานที่มั่นแห่งแรกของการปฏิวัติ และเป็นหัวใจสำคัญของการท่องเที่ยวเชิงประวัติศาสตร์ \'สีแดง\''),
  'jian/torch': ('ประกายไฟแห่งการปฏิวัติ', 'ดินแดนที่ให้กำเนิดวลี \'ประกายไฟเพียงดวงเดียวสามารถจุดไฟทุ่งหญ้าให้ลุกโชนได้\' เป็นอนุสรณ์สถานทางประวัติศาสตร์'),
  'jian/academy': ('สำนักศึกษาไป๋ลู่โจว', 'สำนักศึกษาอายุพันปีบนเกาะกลางแม่น้ำกานแห่งนี้ได้ผลิตบัณฑิตหลวงมาแล้วนับไม่ถ้วน'),
  'jian/pine': ('สนจิ่งกัง', 'ต้นสนแดงที่ตั้งตระหง่านท่ามกลางสายหมอกเป็นสัญลักษณ์ของจิตวิญญาณแห่งขุนเขาและความไม่ย่อท้อ'),
  'nanping/wuyi': ('ภูเขาอู่อี๋', 'ภูเขาอู่อี๋ซึ่งเป็นมรดกโลกของยูเนสโก มีหน้าผาสีแดงและหุบเขาสีเขียวขจี ถือเป็นขุมทรัพย์ทางธรรมชาติและวัฒนธรรม'),
  'nanping/rocktea': ('ชาต้าหงเผา', 'ชาอูหลงต้าหงเผาที่ปลูกบนหน้าผาเป็นหนึ่งในชาที่แพงที่สุดในโลก'),
  'nanping/bambooraft': ('การล่องแพเก้าโค้ง', 'แพไม้ไผ่ล่องไปตามลำธารเก้าโค้งที่คดเคี้ยวไปมาระหว่างหน้าผาสีแดง'),
  'nanping/scholar': ('ปรมาจารย์จูซี', 'จูซี ผู้ก่อตั้งลัทธิขงจื๊อใหม่ ได้สอนอยู่ที่เชิงเขาเหล่านี้'),
  'beijing/great-wall': ('กำแพงเมืองจีน', 'กำแพงเมืองจีนเป็นป้อมปราการที่ยาวที่สุดในโลก มีความยาวกว่า 20,000 กิโลเมตร สร้างขึ้นตลอดหลายศตวรรษเพื่อป้องกันพรมแดนทางเหนือของจีน โดยเฉพาะส่วนปาต้าหลิงใกล้กรุงปักกิ่งซึ่งมีบันไดหินและหอสังเกตการณ์บนสันเขาเป็นส่วนที่ได้รับความนิยมมากที่สุด'),
  'beijing/temple': ('หอเทียนถาน', 'หอเทียนถานเป็นหมู่สิ่งก่อสร้างศักดิ์สิทธิ์ที่จักรพรรดิราชวงศ์หมิงและชิงใช้ประกอบพิธีสวดขอพรจากสวรรค์เพื่อการเก็บเกี่ยวที่ดีในแต่ละปี โดยมีหลังคาทรงกลมสีน้ำเงินสามชั้นที่สร้างขึ้นโดยไม่ใช้ตะปูแม้แต่ตัวเดียว ซึ่งเป็นหนึ่งในสัญลักษณ์ที่โดดเด่นที่สุดของสถาปัตยกรรมจีน'),
  'beijing/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์เทียนหนิงเป็นเจดีย์อิฐสูงประมาณ 57 เมตร 13 ชั้นจากราชวงศ์เหลียว ซึ่งมีลวดลายแกะสลักและตัวเจดีย์ทรงแปดเหลี่ยม ถือเป็นหนึ่งในสิ่งก่อสร้างที่เก่าแก่ที่สุดที่ยังคงหลงเหลืออยู่ในกรุงปักกิ่ง และเป็นพยานถึงประวัติศาสตร์นับพันปีของเมือง'),
  'beijing/opera': ('งิ้วปักกิ่ง', 'งิ้วปักกิ่งเป็นการแสดงละครจีนโบราณที่มีอายุ 200 ปี ซึ่งผสมผสานการร้อง การพูด ศิลปะการต่อสู้ และกายกรรมเข้าไว้ด้วยกัน โดยใบหน้าที่แต่งแต้มสีสัน (เหลียนผู่) ของนักแสดงจะเผยให้เห็นถึงลักษณะของตัวละคร เช่น สีแดงสำหรับความภักดี และสีขาวสำหรับความเจ้าเล่ห์'),
};
